#!/usr/bin/env python3
# This file was generated by Cursor AI on 2026-05-03.
"""
Build stacked histograms of benchmark metrics vs. control from eqsat JSON results.

Each figure uses one set of x-axis bins (percent difference vs. control). Plots use
``100·(control-run)/control`` (sign opposite to ``run-control``), so larger reductions
in ``run`` appear toward the positive side of the axis. Each value is rounded to the
nearest whole percent before binning (sabre-total-bytes: nearest 5%); histogram bins
match that step from the minimum to the maximum rounded value present. For each bin,
bars are stacked
by run type (optimal_ac, optimal_no_ac, heuristic_ac, heuristic_no_ac): segment height
is how many formulas had that run type's value fall in that bin. Samples where that
run type's percent difference vs. control rounds to zero are omitted from the plot data.

Requires: matplotlib, numpy (``pip install matplotlib`` or use a venv).

Example:
  python3 plot_result_histograms.py \\
    --results-dir /path/to/benchmarks/scripts/eqsat/results \\
    --output-dir /path/to/out
"""

from __future__ import annotations

import argparse
import json
import sys
from pathlib import Path
from typing import Any, cast

# Run-type order (bottom -> top in stacked bars)
RUN_TYPES: list[tuple[str, str, str]] = [
    ("Optimal", "optimal_ac.json", "optimal-incomplete-ac"),
    ("Optimal No AC", "optimal_no_ac.json", "optimal-incomplete-noac"),
    ("Heuristic", "heuristic_ac.json", "heuristic-incomplete-ac"),
    ("Heuristic No AC", "heuristic_no_ac.json", "heuristic-incomplete-noac"),
]

RUN_COLORS = {
    "Optimal": "#082A54",
    "Optimal No AC": "#E02B35",
    "Heuristic": "#F0C571",
    "Heuristic No AC": "#59A89C",
}


def _timeout(block: dict[str, Any] | None) -> bool:
    if not block:
        return True
    es = str(block.get("egglog-status", "")).lower()
    gs = str(block.get("gurobi-status", "")).lower()
    return "timeout" in es or "timeout" in gs


def _num(x: Any) -> float | None:
    if x is None:
        return None
    if isinstance(x, (int, float)):
        if isinstance(x, float) and (x != x):  # NaN
            return None
        return float(x)
    return None


def load_results(results_dir: Path) -> tuple[list[str], list[dict[str, Any]]]:
    """Return (ordered filenames, per-index dict of run_label -> metrics dict)."""
    control_path = results_dir / "control.json"
    if not control_path.is_file():
        raise FileNotFoundError(f"Missing {control_path}")

    control_rows = json.loads(control_path.read_text())["results"]
    filenames = [r["filename"] for r in control_rows]
    n = len(filenames)

    per_index: list[dict[str, Any]] = [{"control": r["control"]} for r in control_rows]

    for label, json_name, nested_key in RUN_TYPES:
        path = results_dir / json_name
        if not path.is_file():
            raise FileNotFoundError(f"Missing {path}")
        rows = json.loads(path.read_text())["results"]
        if len(rows) != n:
            raise ValueError(f"{json_name}: expected {n} rows, got {len(rows)}")
        for i, r in enumerate(rows):
            if r.get("filename") != filenames[i]:
                raise ValueError(
                    f"Row order mismatch at index {i}: {json_name} vs control.json"
                )
            block = r.get(nested_key)
            if not isinstance(block, dict):
                raise ValueError(f"{json_name} row {i}: missing {nested_key}")
            per_index[i][label] = block

    return filenames, per_index


def pct_diff(run_v: float, ctrl_v: float) -> float | None:
    if ctrl_v == 0.0:
        if run_v == 0.0:
            return 0.0
        return None
    return 100.0 * (ctrl_v - run_v) / ctrl_v


def collect_metric(
    per_index: list[dict[str, Any]],
    metric_key: str,
    *,
    pct_step: int = 1,
) -> tuple[list[list[float]], int]:
    """
    Collect ``100*(control-run)/control`` per run type, rounded to the nearest ``pct_step``
    percentage points (default 1).

    Returns (one list of values per run type, in RUN_TYPES order) and skipped count
    (rows dropped for timeout, missing metrics, or invalid percent baseline; values
    that round to zero are omitted per run type without incrementing skipped).
    """
    arrays: list[list[float]] = [[] for _ in RUN_TYPES]
    skipped = 0

    for row in per_index:
        ctrl = row["control"]
        if _timeout(ctrl):
            skipped += 1
            continue
        cv = _num(ctrl.get(metric_key))
        if cv is None:
            skipped += 1
            continue

        ok = True
        run_vals: list[float] = []
        for label, _, _ in RUN_TYPES:
            blk = row[label]
            if _timeout(blk):
                ok = False
                break
            rv = _num(blk.get(metric_key))
            if rv is None:
                ok = False
                break
            run_vals.append(rv)

        if not ok:
            skipped += 1
            continue

        diffs: list[float | None] = [pct_diff(rv, cv) for rv in run_vals]
        if any(d is None for d in diffs):
            skipped += 1
            continue
        diffs_f = [cast(float, x) for x in diffs]
        for j, fd in enumerate(diffs_f):
            rounded_pct = int(round(fd / float(pct_step))) * pct_step
            if rounded_pct != 0:
                arrays[j].append(float(rounded_pct))

    return arrays, skipped


def collect_removed_metric(
    per_index: list[dict[str, Any]],
    metric_key: str,
) -> tuple[list[list[float]], int]:
    """
    Collect absolute removals ``control-run`` per run type.

    Returns (one list of values per run type, in RUN_TYPES order) and skipped count.
    Rows are skipped for timeout or missing metrics. Non-positive removals are omitted.
    """
    arrays: list[list[float]] = [[] for _ in RUN_TYPES]
    skipped = 0

    for row in per_index:
        ctrl = row["control"]
        if _timeout(ctrl):
            skipped += 1
            continue
        cv = _num(ctrl.get(metric_key))
        if cv is None:
            skipped += 1
            continue

        ok = True
        run_vals: list[float] = []
        for label, _, _ in RUN_TYPES:
            blk = row[label]
            if _timeout(blk):
                ok = False
                break
            rv = _num(blk.get(metric_key))
            if rv is None:
                ok = False
                break
            run_vals.append(rv)

        if not ok:
            skipped += 1
            continue

        for j, rv in enumerate(run_vals):
            removed = int(round(cv - rv))
            if removed > 0:
                arrays[j].append(float(removed))

    return arrays, skipped


def plot_stacked_hist(
    arrays: list[list[float]],
    title: str,
    xlabel: str,
    out_path: Path,
    *,
    pct_step: int = 1,
) -> None:
    import numpy as np
    import matplotlib

    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    matplotlib.rcParams.update(
        {
            "font.family": "serif",
            "mathtext.fontset": "dejavuserif",
            "font.size": 14,
        }
    )

    labels = [t[0] for t in RUN_TYPES]
    colors = [RUN_COLORS[lbl] for lbl in labels]

    flat = np.concatenate([np.asarray(a, dtype=float) for a in arrays if len(a)])
    if flat.size == 0:
        print(f"Warning: no data for {title}; skipping figure.", file=sys.stderr)
        return

    rmin = int(np.min(flat))
    rmax = int(np.max(flat))
    half = pct_step / 2.0
    # One bin per pct_step from rmin through rmax inclusive.
    edges = np.arange(rmin - half, rmax + half + pct_step, float(pct_step))

    fig, ax = plt.subplots(figsize=(10, 5))
    ax.hist(
        arrays,
        bins=list(edges),
        stacked=True,
        label=labels,
        color=colors,
        edgecolor="white",
        linewidth=0.3,
    )
    # Tight x limits to bin extent only (no default autoscale margin on the ends).
    ax.margins(x=0)
    ax.set_xlim(rmin - half, rmax + half)
    ax.set_xlabel(xlabel)
    ax.set_ylabel("Number of formulas")
    ax.legend(loc="upper right", fontsize=14)
    fig.tight_layout()
    out_path.parent.mkdir(parents=True, exist_ok=True)
    fig.savefig(out_path, dpi=150)
    plt.close(fig)


def main() -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "--results-dir",
        type=Path,
        default=Path(__file__).resolve().parent.parent / "results",
        help="Directory containing control.json and run JSON files",
    )
    parser.add_argument(
        "--output-dir",
        type=Path,
        default=None,
        help="Where to write PNG files (default: <results-dir>/histograms)",
    )
    args = parser.parse_args()
    results_dir = args.results_dir.resolve()
    out_dir = (
        args.output_dir.resolve()
        if args.output_dir
        else results_dir / "histograms"
    )

    try:
        _, per_index = load_results(results_dir)
    except (FileNotFoundError, ValueError, json.JSONDecodeError) as e:
        print(f"Error: {e}", file=sys.stderr)
        return 1

    jobs: list[tuple[str, str, str, int, str]] = [
        (
            "scq",
            "hist_scq_pct_vs_control.png",
            "Percent difference in SCQ vs. control (100·(control-run)/control)",
            1,
            "pct",
        ),
        (
            "num-tl-instructions",
            "hist_num_tl_instructions_pct_vs_control.png",
            "Percent difference in num-tl-instructions vs. control (100·(control-run)/control)",
            1,
            "pct",
        ),
        (
            "num-tl-instructions",
            "hist_num_tl_instructions_removed_vs_control.png",
            "Instructions removed vs. control for num-tl-instructions (control-run)",
            1,
            "removed",
        ),
        (
            "sabre-total-bytes",
            "hist_sabre_total_bytes_pct_vs_control.png",
            "Percent difference in sabre-total-bytes vs. control (100·(control-run)/control, rounded to nearest 5%)",
            5,
            "pct",
        ),
    ]

    for metric_key, fname, title, pct_step, mode in jobs:
        if mode == "pct":
            arrays, skipped = collect_metric(per_index, metric_key, pct_step=pct_step)
        elif mode == "removed":
            arrays, skipped = collect_removed_metric(per_index, metric_key)
        else:
            raise ValueError(f"Unknown mode: {mode}")
        counts = ", ".join(f"{RUN_TYPES[i][0]}={len(arrays[i])}" for i in range(len(RUN_TYPES)))
        if mode == "pct" and pct_step == 1:
            xlabel = "100·(control-run)/control (%, rounded to whole percent)"
        elif mode == "pct":
            xlabel = f"100·(control-run)/control (%, rounded to nearest {pct_step}%)"
        else:
            xlabel = "Instructions removed vs. control (control-run)"
        plot_stacked_hist(arrays, title, xlabel, out_dir / fname, pct_step=pct_step)
        print(f"Wrote {out_dir / fname} ({counts}; skipped_rows={skipped})")

    return 0


if __name__ == "__main__":
    raise SystemExit(main())
